import React from 'react';
import { View, FlatList, StyleSheet, Text, Image } from 'react-native';

const Product = () => {
  const products = [
    { id: 1, name: 'Product 1', image: require('../../assets/images/ip13.jpg') },
    { id: 2, name: 'Product 2', image: require('../../assets/images/ip13.jpg') },
    { id: 3, name: 'Product 3', image: require('../../assets/images/ip13.jpg') },
    { id: 3, name: 'Product 3', image: require('../../assets/images/ip13.jpg') },
  ];

  const renderItem = ({ item }) => {
    return (
      <View style={styles.item}>
        <Image source={item.image} style={styles.image} />
        <Text style={styles.name}>{item.name}</Text>
      </View>
    );
  };

  return (
    <View style={styles.container}>
      <FlatList
        data={products}
        renderItem={renderItem}
        keyExtractor={(item) => item.id.toString()}
        numColumns={2}
      />
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    padding: 10,
  },
  item: {
    flex: 1,
    margin: 10,
    alignItems: 'center',
  },
  image: {
    width: 100,
    height: 100,
    borderRadius: 10,
  },
  name: {
    marginTop: 10,
    fontSize: 16,
    fontWeight: 'bold',
    textAlign: 'center',
  },
});

export default Product;
